module RefModule(
	input clk,
	input enable,
	input reset,
	output reg [3:0] q);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
	if (reset)
		q <= 4'b0000;
	else if (enable) begin
		if (q == 4'b1001)
			q <= 4'b0000;
		else
			q <= q + 1;
	end
end
endmodule
